INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-f29af906-moex-00788', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '甲香雞排店位於社區中，炸雞排時排放的油煙與味道往往導致附近居民抗議，因此環保局對甲香雞排店 開罰並要求加裝符合環保標準的靜電油煙處理設備。若以香雞排價格為縱軸，香雞排數量為橫軸，針對 上述的分析說明，下列何者正確？', '["環保局對雞排店的開罰是屬於確立財產權的作法", "處罰與要求加裝過濾設備會導致市場供給線左移", "環保局可以對居民補貼來減少店家產生外部成本", "雞排店被勒令加裝環保設備即是體現了市場機能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00789', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '我國現行的立法委員選舉，其選舉制度如下：區域立委選舉採（甲）選舉制度，原住民立委選舉採（乙） 選舉制度，全國不分區立委選舉採（丙）選舉制度，下列敘述何者正確？', '["（甲）（乙）選舉制度皆有利於大黨", "（丙）以區域候選人所得票數比例換算政黨席位", "（乙）（丙）皆有婦女保障名額的限制", "（甲）為一個選區只有一人當選的選制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00790', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '若我國總統選舉在某次的票數統計，1號候選人得票率30.6%，2號候選人得票率38.5%，3號候選人得票 率0.7%，4號候選人得票率30.2%，依政治學理及相關法律來看，下列何者是2號候選人在選舉結束後， 最可能面臨的挑戰？', '["得票數未過半，無法當選，須於第二輪投票繼續努力", "得票數未過半，其他候選人可能會提出選舉無效之訴", "得票數未過半，其他候選人可能會提出當選無效之訴", "得票數未過半，可能讓國民認為有代表性不足的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00791', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '小楊時薪400元，為了省錢每餐固定支出60元，某日小楊花了1,500元搭乘高鐵參加兒子的大學畢業典 禮，請同事小許代班 6 小時，事後小楊請小許吃一客 350 元的豪華晚餐作為答謝，自己則點了一客 250 元的精緻晚餐。依上所述判斷，小楊這次參加兒子大學畢業典禮的機會成本是多少？', '["3,900元", "4,250元", "4,440元", "4,560元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00792', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '民國 103 年啟動的「十二年國教」政策，人數最多的基北區高中職免試入學，過去採用「會考總積點」 制度產生爭議；104年承辦免試入學的新北市政府教育局提出「7級總積分」新方案的構想；認為如果104年 放榜未產生爭議，則沿用「會考總積點」的舊方案，若有疑慮，則考慮採用「7級總積分」的新方案。關 於新北市政府教育局的作法，是否符合公共政策決定過程，下列敘述何者正確？', '["符合，因為行政機關提出新方案就已屬於政策合法化的過程", "符合，行政機關可以評估政策的效果來作為修正的判斷依據", "不符合，因為政策評估必須在公共政策規劃之前就必須實施", "不符合，因為若不繼續沿用舊方案，將會違反信賴保護原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00793', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '某輪胎公司與高中汽車修理科進行合作，由該公司提供機械器具作為教學練習使用，讓學生學習時，能 夠將理論與實務結合。該輪胎公司所提供的機械器具，是屬於經濟發展要素中的那一項？', '["自然資本", "人造資本", "企業才能", "人力資本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00794', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '高二的阿文參加學校舉辦的法律營活動，前往各級法院及檢察署參訪。以下為他的參訪心得，依相關法', '["檢察官當庭訓斥被告，並裁定羈押", "在簡易庭中，由五位法官同時開庭", "前往高等法院民事執行處參訪", "檢察官對涉及告訴乃論案件的被告提起公訴  ⑤性侵案件開庭前， 法官將同學請出法庭"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00795', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '小智今年12歲，他所從事的下列何項行為須經法定代理人同意才具有法律效力？', '["接受小華母親贈送的生日禮物", "用母親給的零用錢購買早餐", "和鄰居協議賠償打破鄰居玻璃的費用", "用自己存款繳交班級活動費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00796', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '對於死刑定讞之案件，其執行命令經法務部部長簽署後，依法應由下列何者執行？', '["受命法官", "檢察官", "檢察總長", "檢察長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00797', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '阿強涉嫌綁架撕票案，被法院判處死刑定讞，但辯護律師認為證據不足、法官拒絕被告到庭詰問，且經 專家鑑定發現有新事證足以推翻原判決。該案依相關法律判斷，下列敘述何者正確？', '["律師可向最高法院提出非常上訴", "阿強可委託律師向最高法院聲請再審", "最高檢察署可向最高法院聲請更審", "死刑執行檢察官可向最高法院提出非常上訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
